INSERT INTO `announcements` (`id`, `title`, `content`, `link_url`, `start_date`, `end_date`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 'Website Desa Lambanggelun Tahap Pengembangan', 'Website resmi Desa Lambanggelun sedang dalam tahap pengembangan awal. Beberapa layanan akan diluncurkan bertahap.', NULL, '2026-02-13', NULL, 1, '2026-02-13 01:03:22', '2026-02-13 01:03:22'),
(2, 'Pengambilan Barcode BPNT di Rumah Kepala Dusun', 'Pemerintah Desa Lambanggelun menyampaikan informasi resmi tentang pengambilan Barcode BPNT. Warga desa yang membutuhkan Barcode BPNT diwajibkan untuk mengambilnya di rumah kepala dusun masing-masing. Pengambilan dilakukan dengan membawa KTP sebagai bukti identitas. \r\n\r\nProses ini dilaksanakan secara rutin sesuai jadwal yang telah ditetapkan. Untuk informasi lebih lanjut atau jadwal spesifik, warga dapat menghubungi kepala dusun masing-masing . Perhatikan untuk membawa KTP saat mengambil Barcode BPNT untuk proses pendaftaran.', NULL, '2026-02-20', '2026-02-20', 1, '2026-02-20 05:14:05', '2026-02-20 05:17:14'),
(3, 'Pendaftaran Lomba Krenova Kabupaten Pekalongan', 'Desa Lambanggelun mengumumkan pendaftaran Lomba Krenova Tingkat Kabupaten Pekalongan. Lomba ini terbuka untuk semua warga dan pelajar. Fokusnya pada kreativitas dan inovasi. Informasi lengkap dan link pendaftaran sudah disampaikan melalui saluran resmi desa. Peserta diharapkan mempersiapkan karya yang mencerminkan kemampuan kreatifitas dalam bidang krenova. Tim pemenang akan diumumkan pada tanggal tertentu setelah penilaian. Silakan kunjungi laman resmi Desa Lambanggelun untuk melakukan pendaftaran segera.', 'https://ppid.pekalongankab.go.id/articles?category=pengumuman', '2026-02-05', '2026-02-28', 1, '2026-02-20 09:30:13', '2026-02-20 09:30:13');
