INSERT INTO `news` (`id`, `title`, `slug`, `excerpt`, `thumbnail_path`, `content`, `author_name`, `is_published`, `published_at`, `created_at`, `updated_at`) VALUES
(5, 'Sosialisasi Anti-Judi Remaja di Desa Lambanggelun', 'sosialisasi-anti-judi-remaja-di-desa-lambanggelun', 'KKN UNDIP Semarang melakukan sosialisasi anti-judi online untuk remaja di Desa Lambanggelun, menekankan risiko mental dan kepuasan yang berkembang.', 'news/thumbnails/01KHXF5HT73XW4V3D08V4TH9WD.webp', 'Pada hari Jumat, 15 Oktober 2023, KKN UNDIP Semarang menyelenggarakan sosialisasi program Anti Judi Remaja di Desa Lambanggelun. Acara ini bertujuan meningkatkan kesadaran masyarakat terhadap bahaya judi online, khususnya bagi remaja. Program kerja sosialisasi ini dikemas dengan materi yang kreatif dan interaktif, disampaikan oleh M.Ikhsan, koordinator KKN dari Universitas Diponegoro Semarang. Ia menjelaskan bahwa judi online bukan hanya mengorbankan keuangan, tetapi juga dapat memicu masalah mental seperti hutang mental dan rasa tidak puas yang semakin mendalam. Materi ini dirancang khusus untuk remaja, karena mereka sering menjadi target yang mudah terjebak dalam aktivitas judi online. \r\n\r\nAcara sosialisasi ini diikuti oleh 40 peserta, terdiri dari anggota kelurahan dari lima dusun yang berbeda di Desa Lambanggelun. Kehadiran peserta menunjukkan keprihatinan masyarakat terhadap kondisi remaja yang semakin terancam. Di depan peserta, kepala desa, Abdul Hadi, dan sekretaris desa, Sudim Mukromin, S.Pd., serta beberapa elemen masyarakat setempat, mengikuti langsung pembicaraan. Kepala desa menyatakan dukungannya terhadap program ini sebagai langkah kemandirian desa dalam menangani masalah judi. \r\n\r\nSekretaris desa juga menyampaikan informasi tentang sumber daya yang tersedia untuk pendampingan terhadap remaja yang mungkin terlibat. Sosialisasi ini diikuti dengan diskusi bertahap di mana peserta dibacakan kasus-kasus nyata dan diberikan solusi praktis. Tim KKN UNDIP Semarang menekankan pentingnya pengawasan parental dan penggunaan teknologi secara bijak sebagai cara mencegah remaja terlibat dalam judi online. Hasil dari diskusi ini diharapkan dapat meningkatkan kesadaran dan membentuk perilaku positif di kalangan remaja di Desa Lambanggelun. \r\n\r\nProgram sosialisasi anti-judi online ini merupakan bagian dari upaya KKN UNDIP Semarang untuk mendorong kesejahteraan masyarakat di wilayah pendukungnya. Keberhasilan acara didorong oleh komitmen semua pihak, mulai dari pihak desa hingga mahasiswa KKN, untuk bersama-sama menanggapi tantangan judi online yang semakin membesar.', 'Tim Desa Lambanggelun', 1, '2026-02-20 12:00:00', '2026-02-20 05:07:37', '2026-02-20 05:56:46'),
(6, 'Desa Lambanggelun Rilis Website SID Baru', 'desa-lambanggelun-rilis-website-sid-baru', 'Desa Lambanggelun resmi merilis website SID (Sistem Informasi Desa) yang baru, dibangun oleh pengembang pribadi Khoirul Ulum dalam waktu satu bulan.', 'news/thumbnails/01KJ364TXJTGNSFR0682QZXEYT.webp', 'Desa Lambanggelun telah merilis website SID (Sistem Informasi Desa) yang baru dan modern. Proyek ini dikendalikan oleh Pengurus Desa Lambanggelun, terdiri dari Ketua RW 01, Ketua RW 02, dan Ketua RW 03. Pengembangan web SID ini menempuh masa pengerjaannya sekitar satu bulan. Website SID ini dirancang untuk menyediakan layanan publik yang lebih efisien dan terjangkau bagi warga desa. \r\n\r\nFitur utama yang akan dihidupkan meliputi pengajuan surat online, pengaduan online, serta pembayaran Pajak Bumi dan Bangunan (PBB) secara online. Dengan adanya layanan online ini, warga desa diharapkan dapat mengakses dan menggunakan layanan pemerintah desa secara lebih praktis dan cepat. Penggunaan website SID ini diharapkan dapat mengurangi antrian fisik dan mempermudah proses pelayanan kepada masyarakat desa. \r\n\r\nPengurus Desa Lambanggelun juga menyatakan akan terus meningkatkan dan memperbarui fitur-fitur di website SID sesuai kebutuhan masyarakat desa di kemudian hari.', 'Tim Desa Lambanggelun', 1, '2026-02-22 17:25:00', '2026-02-22 10:25:23', '2026-02-22 10:25:23'),
(7, 'Pembagian BPNT Desa Lambanggelun', 'pembagian-bpnt-desa-lambanggelun', 'Pembagian BPNT ke 300 KPM dari 5 dukuh di Desa Lambanggelun berjalan lancar pada 23 Februari 2024.', 'news/thumbnails/01KJ3692SFE45M7FB1N0EQQ4HS.webp', 'Pembagian Bantuan Non Tunai Perumahan (BPNT) di Desa Lambanggelun pada tanggal 23 Februari 2024 berjalan lancar. Acara ini dilaksanakan mulai pukul 08.00 hingga 16.00 WIB di pusat desa. Terdapat 300 KPM (Kegiatan Pembangunan Masyarakat) yang terbagi dari 5 dukuh dalam wilayah desa. Operasi pembagian berjalan dengan lancar, sesuai dengan rencana yang telah disiapkan.\r\n\r\n Kepala Desa Lambanggelun mengakui program ini sebagai bentuk dukungan ekonomi desa dan kehadiran desa dalam menyelesaikan masalah masyarakat. Program BPNT ini dirancang untuk memberikan bantuan kebutuhan dasar kepada warga miskin, sekaligus meningkatkan kesejahteraan sosial. Pelaksanaannya melibatkan komitmen dan kerja sama dari semua pihak, sehingga mencapai tujuan yang diinginkan. \r\n\r\nKeseluruhan proses pembagian dilakukan dengan penuh keadilan dan transparansi, memastikan setiap penerima mendapatkan bantuan sesuai kebutuhan. Ini merupakan langkah penting dalam upaya desa untuk memperkuat ekonomi masyarakat dan memenuhi kebutuhan pokok yang belum terpenuhi. Kesuksesan acara ini diakui sebagai hasil kerja sama yang baik antara pemerintah desa, pihak terkait, dan warga yang mendapat manfaat. Program BPNT ini diharapkan dapat memberikan dampak positif yang lebih luas pada kesejahteraan warga miskin di Desa Lambanggelun.', 'Tim Desa Lambanggelun', 1, '2026-02-22 17:27:00', '2026-02-22 10:27:42', '2026-02-22 10:27:42'),
(8, 'Musrenbang Desa Lambanggelun Prioritaskan Irigasi dan Karangtaruna', 'musrenbang-desa-lambanggelun-prioritaskan-irigasi-dan-karangtaruna', 'Musyawaran Perencanaan Pembangunan Desa (Musrenbang Desa) di Lambanggelun telah selesai, menetapkan 10 program prioritas, termasuk irigasi saluran tani dan aktivitas Karangtaruna sebagai salah satu kunci.', 'news/thumbnails/01KJ36CYXWW8VGPMP00DQMH8YR.webp', 'Musyawaran Perencanaan Pembangunan Desa (Musrenbang Desa) di Desa Lambanggelun telah diadakan dengan sukses. Dalam acara ini, para pemangku kepentingan desa serta masyarakat berpartisipasi aktif dalam menetapkan 10 program pembangunan yang menjadi prioritas untuk tahun depan. Program-program ini dirancang untuk memenuhi kebutuhan dasar dan mengembangkan potensi desa.\r\n\r\nSalah satu program kunci yang ditetapkan adalah pengembangan irigasi saluran tani. Dengan kondisi tanah yang luas, infrastruktur irigasi yang memadai diperlukan untuk meningkatkan produktivitas pertanian, mengurangi risiko kekeringan, dan meningkatkan kesejahteraan petani. Pengadaan atau perbaikan saluran saluran irigasi menjadi tujuan utama dalam program ini.\r\n\r\nProgram lain yang mendapat perhatian adalah aktivitas Karangtaruna. Karangtaruna merupakan wadah untuk pemuda yang ingin berkontribusi dalam pembangunan desa melalui keterampilan dan aktifitas sosial. Program ini menekankan pengembangan potensi masyarakat muda sebagai warga desa yang mandiri dan berpartisipatif.\r\n\r\nDengan menetapkan kedua program ini sebagai prioritas, Desa Lambanggelun menekankan komitmennya untuk memastikan akses irigasi yang baik untuk petani dan pengembangan potensi generasi muda. Peningkatan kesejahteraan masyarakat dan pembangunan ekonomi desa diharapkan menjadi hasil akhir dari pelaksanaan program-program prioritas ini.\r\n\r\nSemoga pelaksanaan program-program prioritas Musrenbang Desa ini dapat memberikan manfaat nyata bagi seluruh warga desa Lambanggelun.', 'Tim Desa Lambanggelun', 1, '2026-02-22 17:29:00', '2026-02-22 10:29:49', '2026-02-22 10:29:49'),
(9, 'Petani Lambanggelun Tanam Varietas Unggul Padi', 'petani-lambanggelun-tanam-varietas-unggul-padi', 'Petani Lambanggelun berhasil menanam varietas unggul padi setelah saluran irigasi selesai. Ini meningkatkan produksi dan kualitas padi.', 'news/thumbnails/01KJ36GRMEGH21HEAVHTRZJA7E.webp', 'Petani di Desa Lambanggelun baru-baru ini menanam varietas padi unggul yang dipercaya meningkatkan hasil panen. Varietas ini dirasakan memiliki karakteristik seperti tumbuh lebih tinggi, resisten terhadap penyakit, serta menghasilkan biji yang lebih banyak. Proses penanaman dilakukan dengan teliti, mulai dari pemilihan bibit yang berkualitas hingga perawatan tanaman dengan baik.\r\nSaluran irigasi yang telah selesai berfungsi dengan baik, memungkinkan petani untuk menyediakan air secara teratur. \r\n\r\nIni mengurangi risiko kekeringan dan meningkatkan kematangan padi. Petani menekankan pentingnya pemeliharaan rutin seperti pemupukan dan pencegahan hama untuk memastikan varietas unggul dapat mencapai potensi yang terbaik.\r\nHasil dari penanaman varietas unggul ini diharapkan dapat meningkatkan pendapatan petani. Komunitas Lambanggelun terus berusaha memperluas penggunaan varietas ini untuk mendukung pertumbuhan agribisnis lokal. Pelatihan teknis dari pemerintah juga diadakan untuk memperkuat kemampuan petani dalam mengelola tanaman varietas unggul ini.\r\n\r\nPetani menyatakan kepuasan dengan kemajuan yang dirasakan. Keberhasilan ini dianggap sebagai langkah positif dalam meningkatkan produktivitas pertanian di desa. Kemampuan petani untuk memanfaatkan saluran irigasi yang lengkap menjadi kunci utama dalam mencapai hasil yang lebih baik.', 'Tim Desa Lambanggelun', 1, '2026-02-22 17:31:00', '2026-02-22 10:31:53', '2026-02-22 10:31:53'),
(10, 'Inagurasi Eco Cuan sebagai Sub Unit BUMDES', 'inagurasi-eco-cuan-sebagai-sub-unit-bumdes', 'Desa Lambanggelun inaugurates Eco Cuan, a digital platform transforming traditional waste banks into accessible financial tools, boosting community engagement and environmental responsibility.', 'news/thumbnails/01KN2FCJTJA7VEAEPWN5RC22B5.webp', 'Desa Lambanggelun merayakan pelantikan Eco Cuan sebagai Sub Unit BUMDES. Eco Cuan merupakan aplikasi inisiatif Tim Khoirul Ulum CS yang bertujuan menjadikan bank sampah konvensional menjadi digital. Dengan platform ini, masyarakat dapat lebih mudah melakukan transaksi dan mengelola sampah mereka secara online. Sistem digital ini diharapkan meningkatkan kepedulian masyarakat terhadap pentingnya menjaga kebersihan lingkungan, terutama dalam mengelola sampah. Secara tidak langsung, kemampuan ekonomi masyarakat juga diperkaya karena bank sampah digital dapat memberikan akses ke berbagai kemudahan keuangan. Pelantikan Eco Cuan ini merupakan langkah strategis Desa Lambanggelun untuk mendukung program BUMDES dan meningkatkan kesejahteraan warga melalui inovasi teknologi yang berkelanjutan. Tim Khoirul Ulum CS terus bekerja sama dengan Desa Lambanggelun untuk memastikan Eco Cuan berfungsi dengan baik dan mencapai tujuan program digitalisasi bank sampah yang diharapkan dapat mempengaruhi wilayah lain.\r\n\r\nEco Cuan dianggap sebagai solusi yang tepat untuk mengatasi tantangan bank sampah konvensional yang seringkali kurang terjangkau. Dengan adanya aplikasi ini, warga Desa Lambanggelun diharapkan lebih mudah dan nyaman dalam melakukan aktivitas ekonomi terkait sampah, sekaligus memperkuat peran BUMDES dalam membangun ekonomi lokal yang lebih sehat. Pelantikan ini juga diikuti dengan pelatihan dan dukungan teknis dari Tim Khoirul Ulum CS untuk memastikan semua fungsionalitas platform digital dapat diakses dan digunakan dengan maksimal oleh komunitas setempat. Desa Lambanggelun menantikan Eco Cuan dapat memberikan dampak positif yang nyata pada kesejahteraan ekonomi dan kemandirian warga di desa ini.', 'Tim Desa Lambanggelun', 1, '2026-03-31 17:32:00', '2026-03-31 10:32:42', '2026-03-31 10:34:58');
