INSERT INTO `village_activities` (`id`, `title`, `slug`, `category`, `activity_date`, `location`, `person_in_charge`, `status`, `budget`, `summary`, `description`, `cover_image_path`, `document_path`, `created_at`, `updated_at`) VALUES
(1, 'Pembangunan Drainase Lingkungan Dusun Bojongireng', 'pembangunan-drainase-lingkungan-dusun-bojongireng', 'Infrastruktur', '2025-01-20', 'Dusun Bojongireng', 'Kasi Kesejahteraan', 'Selesai', '185000000.00', 'Pembangunan saluran drainase untuk mengurangi genangan saat musim hujan.', 'Kegiatan pembangunan drainase dilakukan sepanjang 450 meter di titik rawan genangan sebagai program prioritas infrastruktur desa.', 'https://images.unsplash.com/photo-1494522358652-f30e61a60313?auto=format&fit=crop&w=1200&q=80', NULL, '2026-02-13 01:03:22', '2026-02-13 01:03:22'),
(2, 'Pelatihan UMKM dan Digital Marketing Warga', 'pelatihan-umkm-dan-digital-marketing-warga', 'Pemberdayaan Masyarakat', '2025-04-12', 'Balai Desa Lambanggelun', 'Kasi Pelayanan', 'Selesai', '47500000.00', 'Pelatihan penguatan kapasitas UMKM desa untuk pemasaran digital.', 'Program pelatihan mencakup branding produk, foto produk, strategi marketplace, dan literasi keuangan bagi pelaku UMKM desa.', 'https://images.unsplash.com/photo-1556761175-4b46a572b786?auto=format&fit=crop&w=1200&q=80', NULL, '2026-02-13 01:03:22', '2026-02-13 01:03:22'),
(3, 'Normalisasi Saluran Irigasi Pertanian', 'normalisasi-saluran-irigasi-pertanian', 'Pertanian', '2025-08-08', 'Area Sawah Dusun Simendem', 'Kasi Pemerintahan', 'Berjalan', '96000000.00', 'Kegiatan normalisasi saluran irigasi sebagai dukungan produktivitas pertanian.', 'Kegiatan meliputi pembersihan sedimentasi, perbaikan tanggul kecil, dan penataan alur irigasi primer menuju petak sawah warga.', 'https://images.unsplash.com/photo-1500937386664-56d1dfef3854?auto=format&fit=crop&w=1200&q=80', NULL, '2026-02-13 01:03:22', '2026-02-13 01:03:22'),
(4, 'Festival Budaya dan Kesenian Desa', 'festival-budaya-dan-kesenian-desa', 'Sosial Budaya', '2026-02-02', 'Lapangan Desa Lambanggelun', 'Sekretaris Desa', 'Perencanaan', NULL, 'Agenda budaya tahunan sebagai ruang ekspresi seni warga desa.', 'Kegiatan festival budaya disiapkan untuk menampilkan kesenian lokal, bazar UMKM, serta promosi potensi desa ke masyarakat luas.', 'https://images.unsplash.com/photo-1472653431158-6364773b2a56?auto=format&fit=crop&w=1200&q=80', NULL, '2026-02-13 01:03:22', '2026-02-13 01:03:22'),
(5, 'Peringatan HUT RI Desa Lambanggelun', 'peringatan-hut-ri-desa-lambanggelun', 'Sosial', '2026-02-22', 'Lapangan SDN 02 Lambanggelun', 'Karang taruna', 'Berjalan', NULL, NULL, NULL, NULL, NULL, '2026-02-22 08:00:26', '2026-02-22 08:00:26');
